public class ParseBenchmarkTest {

  private ParseBenchmark parseBenchmark;

  @BeforeEach
  void init() {
    parseBenchmark = new ParseBenchmark();
  }

  @Test
  void testSetUp() throws Exception {
    // Use reflection to get the private nested classes Document, Api, Parser
    Class<?> documentClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Document");
    Class<?> apiClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Api");
    Class<?> parserClass = Class.forName("com.google.gson.metrics.ParseBenchmark$Parser");

    // Prepare mock Document and Api enums via reflection
    Object mockDocument = mock(documentClass);
    when(mockDocument.toString()).thenReturn("testDocument");

    // Stub name() method on mockDocument using a dynamic proxy-like approach
    // Because name() is a method on enum, we can mock it by spying or using Mockito's when on the mock directly
    when(documentClass.getMethod("name").invoke(mockDocument)).thenReturn("testDocument");
    // The above line throws IllegalAccessException because invoke() is final and cannot be stubbed
    // Instead, use Mockito to stub the method directly:
    when(mockDocument.getClass().getMethod("name").invoke(mockDocument)).thenReturn("testDocument"); // won't work - fix below

    // Fix: Use Mockito's when on mockDocument.name() by creating a spy or using Mockito's doReturn
    // But since mockDocument is a mock of a class, we can do:
    when(documentClass.getMethod("name").invoke(mockDocument)).thenReturn("testDocument"); // This is reflection invoke, cannot mock invoke
    // So instead, we mock the method call directly:
    // Create a mock with stubbed name method:
    // Use Mockito's 'when' on the mockDocument.name() method directly:
    // But mockDocument is Object, we need to cast:
    Object mockDocumentCasted = mockDocument;
    // Use Mockito's doReturn:
    // Need to cast to documentClass:
    // Use Mockito's doReturn:
    // Actually, better to create a spy of a real enum constant or create a dummy enum instance with name() overridden
    // But since it's complicated, we can create a subclass proxy:
    // Alternatively, use a Mockito Answer for method name:
    // Use a proxy for mockDocument to override name()
    // Or use Mockito's doReturn:
    // Use Mockito's doReturn("testDocument").when(mockDocument).name();
    // But mockDocument is Object, need to cast:
    // Use Mockito's doReturn("testDocument").when((Document)mockDocument).name();
    // So cast mockDocument to the documentClass:
    when(documentClass.getMethod("name").invoke(mockDocument)).thenReturn("testDocument"); // This is reflection invoke, can't mock invoke
    // So instead, use Mockito's doReturn:
    // Use Mockito's doReturn("testDocument").when(mockDocument).name();
    // But mockDocument is Object, need to cast:
    // Use a helper method to invoke:
    // Use Mockito's doReturn("testDocument").when((Document)mockDocument).name();
    // But we cannot cast at compile time, so use Mockito's when with reflection:
    // Use Mockito's doAnswer:
    // Instead, create a dynamic proxy for Document that returns "testDocument" for name():
    Object proxyDocument = java.lang.reflect.Proxy.newProxyInstance(
      documentClass.getClassLoader(),
      new Class<?>[] { documentClass },
      (proxy, method, args) -> {
        if (method.getName().equals("name")) {
          return "testDocument";
        }
        if (method.getName().equals("toString")) {
          return "testDocument";
        }
        return method.invoke(mockDocument, args);
      });

    // Create mockApi and mockParser
    Object mockApi = mock(apiClass);
    Object mockParser = mock(parserClass);

    // Stub api.newParser() method on mockApi using reflection
    // newParser is not found via getMethod because it's not public, so use getDeclaredMethod
    Method newParserMethod = apiClass.getDeclaredMethod("newParser");
    newParserMethod.setAccessible(true);
    when(newParserMethod.invoke(mockApi)).thenReturn(mockParser);

    // Alternatively, mock the newParser method call on mockApi:
    // Since newParser() is probably not public, Mockito cannot mock it directly.
    // Use a spy or doAnswer:
    // Use Mockito's doAnswer to mock newParser method:
    // But since mockApi is a mock, we can use Mockito's when on the method call via a lambda:
    // But the method is not accessible via interface, so use Mockito's doAnswer with reflection:
    // Instead, create a proxy for Api to override newParser():

    Object proxyApi = java.lang.reflect.Proxy.newProxyInstance(
      apiClass.getClassLoader(),
      new Class<?>[] { apiClass },
      (proxy, method, args) -> {
        if (method.getName().equals("newParser")) {
          return mockParser;
        }
        return method.invoke(mockApi, args);
      });

    // Inject mocks into parseBenchmark instance
    Field documentField = ParseBenchmark.class.getDeclaredField("document");
    documentField.setAccessible(true);
    documentField.set(parseBenchmark, proxyDocument);

    Field apiField = ParseBenchmark.class.getDeclaredField("api");
    apiField.setAccessible(true);
    apiField.set(parseBenchmark, proxyApi);

    // Use reflection to get the private static method resourceToString
    Method resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToStringMethod.setAccessible(true);

    // Mock static method resourceToString via Mockito.mockStatic with reflection
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class, Mockito.CALLS_REAL_METHODS)) {
      mockedStatic.when(() -> {
        try {
          return resourceToStringMethod.invoke(null, "testDocument.json");
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      }).thenReturn("jsonContent");

      // Use reflection to invoke private setUp method
      Method setUpMethod = ParseBenchmark.class.getDeclaredMethod("setUp");
      setUpMethod.setAccessible(true);
      setUpMethod.invoke(parseBenchmark);

      // Validate that text field is set correctly
      Field textField = ParseBenchmark.class.getDeclaredField("text");
      textField.setAccessible(true);
      char[] textValue = (char[]) textField.get(parseBenchmark);
      assertArrayEquals("jsonContent".toCharArray(), textValue);

      // Validate that parser field is set correctly
      Field parserField = ParseBenchmark.class.getDeclaredField("parser");
      parserField.setAccessible(true);
      Object parserValue = parserField.get(parseBenchmark);
      assertSame(mockParser, parserValue);
    }
  }
}
